package mpesa

// DefaultSandboxPublicKey is the sandbox platform public key supplied by M-Pesa OpenAPI.
const DefaultSandboxPublicKey = ""

// DefaultOpenAPIPublicKey is the live/OpenAPI platform public key supplied by M-Pesa OpenAPI.
const DefaultOpenAPIPublicKey = ""

func defaultPublicKeyForEnvironment(environment Environment) string {
	if environment == EnvironmentOpenAPI {
		return DefaultOpenAPIPublicKey
	}
	return DefaultSandboxPublicKey
}
